scwin.sbm_saveDetail_submitdone = async function(e) {
    await $c.gus.cfAlertMsg(MSG_CM_INF_001);
    await scwin.f_Retrieve();

    for (let i = 0; i < ds_oilInOut.getRowCount(); i++) {
        for (let j = 0; j < ds_chkList.getRowCount(); j++) {
            if (ds_chkList.getCellData(j, "reqRegDt") == ds_oilInOut.getCellData(i, "reqRegDt") &&
                ds_chkList.getCellData(j, "clntNo") == ds_oilInOut.getCellData(i, "clntNo") &&
                ds_chkList.getCellData(j, "reqSeq") == ds_oilInOut.getCellData(i, "reqSeq")) {
                ds_oilInOut.setCellData(i, "chk", "T");
            }
        }
    }
};

